INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 11, 'teens', 1, 'Why did Jephthah''s half-brothers drive him away from his home?', 'He was the son of a strange woman and they would not share their father''s inheritance with him', 'He stole their cattle', 'He allied with Israel''s enemies', 'He refused to worship at the tabernacle', 'a', 'Judges 11:2 — "And Gilead''s wife bare him sons; and his wife''s sons grew up, and they thrust out Jephthah, and said unto him, Thou shalt not inherit in our father''s house; for thou art the son of a strange woman."'),
('Judges', 11, 'teens', 2, 'What did Jephthah argue to the king of Ammon about who rightfully owned the disputed territory?', 'Israel took the land from the Amorites, not from Ammon, so it belonged to Israel', 'Abraham had purchased the land centuries before', 'God gave the land directly to Gilead by name', 'The land was uninhabited when Israel arrived', 'a', 'Judges 11:23-24 — "So now the LORD God of Israel hath dispossessed the Amorites from before his people Israel, and shouldest thou possess it?" Jephthah argued the land came from the Amorites, not Ammon.'),
('Judges', 11, 'teens', 3, 'Who first came out of Jephthah''s house to meet him when he returned from victory?', 'His daughter, his only child', 'His wife', 'His servants', 'A group of young men', 'a', 'Judges 11:34 — "And Jephthah came to Mizpeh unto his house, and, behold, his daughter came out to meet him with timbrels and with dances: and she was his only child."'),
('Judges', 11, 'teens', 4, 'What did Jephthah''s daughter request before her fate was sealed?', 'Two months to bewail her virginity in the mountains', 'Permission to go to the tabernacle to pray', 'A chance to say farewell to all the tribes of Israel', 'That her father would not make the vow', 'a', 'Judges 11:37 — "And she said unto her father, Let this thing be done for me: let me alone two months, that I may go up and down upon the mountains, and bewail my virginity."'),
('Judges', 11, 'teens', 5, 'What became a custom in Israel following the events concerning Jephthah''s daughter?', 'The daughters of Israel went four days each year to lament', 'Israel banned rash vows', 'The tabernacle held an annual fast in her memory', 'Young women were forbidden from battle sendoffs', 'a', 'Judges 11:40 — "And it was a custom in Israel, That the daughters of Israel went yearly to lament the daughter of Jephthah the Gileadite four days in a year."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 11, 'adults', 1, 'What does the land of Tob, where Jephthah fled, represent in his story?', 'A pagan territory where rejected outcasts could find community outside Israel''s covenant structure', 'A priestly city of refuge', 'A Canaanite stronghold he helped defend', 'A place of divine training like Moses in Midian', 'a', 'Judges 11:3 — "Then Jephthah fled from his brethren, and dwelt in the land of Tob: and there were gathered vain men to Jephthah, and went out with him." Tob lay in the Transjordan frontier, outside normal Israelite governance.'),
('Judges', 11, 'adults', 2, 'How many years does Jephthah''s historical argument in his embassy span, and what does this imply about Israel''s claim?', 'Three hundred years, showing an ancient and well-established Israelite possession', 'Forty years, matching the wilderness generation', 'One hundred years, spanning Saul to David', 'Seventy years, the span of a generation', 'a', 'Judges 11:26 — "While Israel dwelt in Heshbon and her towns...three hundred years? why therefore did ye not recover them within that time?" A three-century uncontested possession was a powerful legal and historical argument.'),
('Judges', 11, 'adults', 3, 'What is the theological significance of the Spirit of the LORD coming upon Jephthah in verse 29?', 'It validates him despite his social illegitimacy, showing God''s gifts are not bound by human social structures', 'It guarantees absolute success without any further conditions', 'It means Jephthah became a prophet as well as a judge', 'It cancels his rash vow retrospectively', 'a', 'Judges 11:29 — "Then the Spirit of the LORD came upon Jephthah." God''s Spirit coming on a social outcast parallels Gideon and Samson, showing grace chooses the unlikely.'),
('Judges', 11, 'adults', 4, 'How does Jephthah''s reference to "Chemosh your god" in verse 24 function in his diplomatic argument?', 'He appears to grant the existence of Chemosh to make a comparative legal argument, not affirm pagan theology', 'He worships Chemosh alongside the LORD', 'He claims Chemosh has given the land to Israel', 'He uses it as a curse against Ammon', 'a', 'Judges 11:24 — "Wilt not thou possess that which Chemosh thy god giveth thee to possess?" Jephthah uses a comparative legal argument: just as Ammon accepts what its god gives, Israel has right to what the LORD gave Israel.'),
('Judges', 11, 'adults', 5, 'What is the dominant scholarly debate regarding the fate of Jephthah''s daughter?', 'Whether she was literally offered as a burnt sacrifice or consecrated to perpetual virginity at the tabernacle', 'Whether the story is historical or purely allegorical', 'Whether Jephthah was a legitimate judge of Israel', 'Whether her mother is identified elsewhere in Scripture', 'a', 'Judges 11:39 — "he did with her according to his vow...and she knew no man." The phrase "knew no man" leads many scholars to argue for perpetual virginity rather than death, while others insist the burnt-offering language demands literal interpretation.'),
('Judges', 11, 'adults', 6, 'What does the book of Hebrews say about Jephthah that complicates simple moral condemnation of him?', 'Hebrews 11:32 lists Jephthah among heroes of faith alongside Gideon, Barak, and Samson', 'Hebrews warns Jephthah is an example of rash prayer', 'Hebrews says Jephthah''s vow was later annulled by a priest', 'Hebrews does not mention Jephthah at all', 'a', 'Hebrews 11:32 — "And what shall I more say? for the time would fail me to tell of Gedeon, and of Barak, and of Samson, and of Jephthae." His listing among faith heroes shows God credits overall faith even when a servant makes grave errors.'),
('Judges', 11, 'adults', 7, 'What does Jephthah''s negotiated return from Tob tell us about covenant community and pragmatic leadership in ancient Israel?', 'The elders of Gilead were willing to restore an outcast as head when military crisis demanded it, showing authority was conditional and pragmatic', 'Israel had no formal mechanism for restoring exiles', 'Jephthah demanded unconditional reinstatement before fighting', 'The priesthood approved Jephthah''s return through divination', 'a', 'Judges 11:8-9 — "And the elders of Gilead said unto Jephthah...Therefore we turn again to thee now...And Jephthah said unto the elders of Gilead, If ye bring me home again to fight...then I will be your head." The negotiation reflects a contractual view of leadership.'),
('Judges', 11, 'adults', 8, 'What does Jephthah''s invocation of the LORD as judge in verse 27 reveal about his theology?', 'He held a high view of God as impartial arbiter between nations, a divine judge above both Ammon and Israel', 'He believed God only judged Israel and ignored the nations', 'He was appealing to international arbitration treaties', 'He doubted the LORD''s power and sought a human judge instead', 'a', 'Judges 11:27 — "Wherefore I have not sinned against thee, but thou doest me wrong to war against me: the LORD the Judge be judge this day between the children of Israel and the children of Ammon." This is a remarkable invocation of God as universal judge.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 12, 'teens', 1, 'What did Ephraim threaten to do to Jephthah and his house?', 'Burn his house down upon him', 'Take him captive to Shiloh', 'Banish him from Israel', 'Kill all of Gilead''s livestock', 'a', 'Judges 12:1 — "we will burn thine house upon thee with fire." The Ephraimites threatened arson against Jephthah''s household.'),
('Judges', 12, 'teens', 2, 'How did Jephthah counter Ephraim''s complaint that he had not called them to fight?', 'He said he had called them but they did not save him, so he risked his life and the LORD delivered Ammon to him', 'He said Ephraim was too far away to summon in time', 'He said God had forbidden him to call for reinforcements', 'He acknowledged his error and made peace with them', 'a', 'Judges 12:2-3 — "I and my people were at great strife with the children of Ammon; and when I called you, ye delivered me not out of their hands. And when I saw that ye delivered me not, I put my life in my hands."'),
('Judges', 12, 'teens', 3, 'How many years did Jephthah judge Israel?', 'Six years', 'Eight years', 'Twenty years', 'Forty years', 'a', 'Judges 12:7 — "And Jephthah judged Israel six years. Then died Jephthah the Gileadite, and was buried in the cities of Gilead."'),
('Judges', 12, 'teens', 4, 'Which of the minor judges after Jephthah had thirty sons and thirty daughters whom he gave in marriage, and thirty sons riding on thirty donkeys?', 'Ibzan of Bethlehem', 'Elon the Zebulonite', 'Abdon the Pirathonite', 'Jair the Gileadite', 'a', 'Judges 12:8-9 — "And after him Ibzan of Beth-lehem judged Israel. And he had thirty sons, and thirty daughters, whom he sent abroad, and took in thirty daughters from abroad for his sons."'),
('Judges', 12, 'teens', 5, 'How many sons and grandsons did Abdon the Pirathonite have, and what did they ride?', 'Forty sons and thirty nephews riding on seventy ass colts', 'Twenty sons and twenty grandsons riding on donkeys', 'Thirty sons and thirty grandsons riding on horses', 'Forty sons and thirty grandsons riding on camels', 'a', 'Judges 12:14 — "And he had forty sons and thirty nephews, that rode on threescore and ten ass colts: and he judged Israel eight years."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 12, 'adults', 1, 'What does the Shibboleth episode reveal about dialect variation in ancient tribal Israel?', 'Different tribes of Israel spoke recognisably distinct dialects, such that a single phoneme could betray tribal identity', 'All Israelites spoke one unified dialect and only Ephraimites had a foreign accent', 'The Ephraimites were actually Canaanites pretending to be Israelites', 'The test was based on a foreign language unknown to most Israelites', 'a', 'Judges 12:6 — "for he could not frame to pronounce it right." The inability to produce the /sh/ sound in "Shibboleth" reflects genuine phonological variation across Israelite tribal dialects.'),
('Judges', 12, 'adults', 2, 'What does Ephraim''s repeated complaint (also seen in Judges 8 with Gideon) reveal about intertribal politics in the period of the judges?', 'Ephraim had a persistent sense of tribal superiority and expected to be included in major military campaigns', 'Ephraim was legally required to lead every battle', 'Ephraim was the weakest tribe and sought glory it could not win militarily', 'Ephraim''s complaints were always justified and acknowledged by the judges', 'a', 'Judges 12:1 — "Why passedst thou over to fight against the children of Ammon, and didst not call us to go with thee?" In Judges 8:1 Ephraim made the same complaint to Gideon. Gideon appeased them; Jephthah did not, resulting in civil war.'),
('Judges', 12, 'adults', 3, 'How does Jephthah''s handling of the Ephraimite challenge contrast with Gideon''s in Judges 8, and what does this tell us about leadership?', 'Gideon used a soft answer to turn away wrath; Jephthah''s blunt refusal of blame escalated to civil war, showing how a leader''s temperament shapes communal outcomes', 'Jephthah and Gideon both went to war against Ephraim', 'Gideon also fought Ephraim but it is not recorded', 'Jephthah was righteous and Gideon was wrong to appease Ephraim', 'a', 'Judges 8:3 — Gideon''s "soft answer" satisfied Ephraim. Jephthah''s confrontational reply in Judges 12:2-3 led to 42,000 deaths. The contrast illustrates Proverbs 15:1: "A soft answer turneth away wrath."'),
('Judges', 12, 'adults', 4, 'What is the lexical meaning of "Shibboleth" and what two meanings has it carried in subsequent history?', 'An ear of grain or a flowing stream; later used to mean any test of belonging or linguistic marker of group identity', 'A battle cry meaning "victory to the LORD"; later used to mean any religious oath', 'A type of weapon; later used to mean a military password', 'A Canaanite word for idol; later used to mean any pagan practice', 'a', 'Judges 12:6 — "Say now Shibboleth." The Hebrew word means both "ear of grain" and "flowing stream." Historically, it has given English the word "shibboleth" — a linguistic or cultural test used to identify insiders and outsiders.'),
('Judges', 12, 'adults', 5, 'What is the theological irony of Ephraim, whose ancestor received the greater blessing from Jacob (Gen. 48), being decimated in a civil war within Israel?', 'The tribe that inherited the patriarchal blessing of preeminence was brought low by pride and internecine strife', 'Ephraim had forfeited its blessing by worshipping Canaanite idols', 'The decimation of Ephraim fulfilled a specific prophecy', 'Ephraim was being punished for the sins of Joseph', 'a', 'Genesis 48:19-20 gives Ephraim the greater blessing over Manasseh. Judges 12:6 records 42,000 Ephraimites slain by fellow Israelites, a tragic fulfillment of the warning that pride goes before a fall (Proverbs 16:18).'),
('Judges', 12, 'adults', 6, 'What does the rapid succession of minor judges (Ibzan, Elon, Abdon) in a single chapter suggest about the narrative structure of Judges?', 'The author is accelerating the narrative to reach the Samson cycle, using minor judges as transitional material', 'These judges were more important than the major judges', 'The minor judges indicate a period of total spiritual revival', 'Each minor judge ruled a different region with no overlap', 'a', 'Judges 12:8-15 compresses three judgeships into eight verses. The formulaic treatment contrasts sharply with the extended Jephthah and Samson narratives, serving as a literary bridge.'),
('Judges', 12, 'adults', 7, 'What does the detail that Ibzan sent his thirty daughters abroad and brought in thirty foreign daughters for his sons suggest about marriage practices in this period?', 'Exogamous marriage alliances were used politically by leaders to build cross-tribal coalitions', 'Ibzan was disobeying the Mosaic law forbidding intermarriage with Canaanites', 'The daughters were sent as tribute to foreign kings', 'This was a normal religious requirement for judges of Israel', 'a', 'Judges 12:9 — "he sent abroad, and took in thirty daughters from abroad for his sons." Whether these marriages were within Israel or outside it is debated, but the pattern reflects the use of marriage for political alliance-building common in the ancient Near East.'),
('Judges', 12, 'adults', 8, 'What does the cumulative toll of internecine bloodshed in Judges 12 (42,000 dead) reveal about the spiritual state of Israel at this time?', 'Israel had so thoroughly abandoned covenant unity that the tribes were willing to slaughter one another, accelerating the very chaos the judges were meant to prevent', 'The civil war was a necessary purification of Israel', 'God had decreed the civil war as punishment for Ephraim''s idolatry', 'The 42,000 figure is symbolic and should not be read literally', 'a', 'Judges 12:6 — "there fell at that time of the Ephraimites forty and two thousand." Internecine killing on this scale contrasts starkly with the covenant ideal of Israel as one people, illustrating the downward spiral the book of Judges traces.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 13, 'teens', 1, 'What three things was Manoah''s wife told to avoid during her pregnancy?', 'Wine, strong drink, and all unclean things', 'Meat, leaven, and contact with the dead', 'Idols, incense, and pagan feasts', 'Salt, oil, and foreign grain', 'a', 'Judges 13:4 — "Now therefore beware, I pray thee, and drink not wine nor strong drink, and eat not any unclean thing."'),
('Judges', 13, 'teens', 2, 'What did Manoah offer the angel, and how did the angel instruct him to present it?', 'A kid goat; offer it as a burnt offering to the LORD rather than to himself', 'A lamb; sacrifice it at the tabernacle first', 'Bread and wine; pour them on the altar', 'An ox; give it to the priests of Shiloh', 'a', 'Judges 13:16 — "And the angel of the LORD said unto Manoah...offer it unto the LORD." The angel refused to eat food meant for him but directed it be offered to God.'),
('Judges', 13, 'teens', 3, 'What miraculous sign occurred when Manoah offered the sacrifice on the rock?', 'The flame ascended toward heaven and the angel ascended in the flame', 'Fire came down from heaven and consumed the altar', 'A rainbow appeared in the sky', 'The rock split open and water flowed out', 'a', 'Judges 13:20 — "For it came to pass, when the flame went up toward heaven from off the altar, that the angel of the LORD ascended in the flame of the altar."'),
('Judges', 13, 'teens', 4, 'Why was Manoah afraid after the angel ascended in the flame?', 'He thought he and his wife would surely die because they had seen God', 'He feared the Philistines had seen the miracle', 'He worried the vow was invalid because the angel had left', 'He thought the sacrifice had been rejected', 'a', 'Judges 13:22 — "And Manoah said unto his wife, We shall surely die, because we have seen God." His fear reflects the ancient belief that no man could see God and live.'),
('Judges', 13, 'teens', 5, 'What name was given to the angel when Manoah asked for it?', 'The angel said his name was secret (wonderful)', 'The angel said his name was Gabriel', 'The angel refused to give any name at all', 'The angel said his name was Michael', 'a', 'Judges 13:18 — "And the angel of the LORD said unto him, Why askest thou thus after my name, seeing it is secret?" The Hebrew word translated "secret" is also rendered "wonderful" in some versions.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 13, 'adults', 1, 'What is the theological significance of Manoah''s wife being described as barren before the angelic announcement?', 'It places Samson''s birth in the pattern of miraculous divine provision like Isaac, Jacob, Joseph, and later Samuel and John the Baptist', 'It means Samson was not truly human but had a divine nature', 'It proves Manoah was being punished for a secret sin', 'It is simply a medical detail with no theological significance', 'a', 'Judges 13:2-3 — "his wife was barren...Behold now, thou art barren...but thou shalt conceive." Barren mothers who bear deliverers is a recurring biblical motif: Sarah (Gen. 18), Rachel (Gen. 30), Hannah (1 Sam. 1), Elizabeth (Luke 1).'),
('Judges', 13, 'adults', 2, 'What does the description of the angel as "very terrible" (awesome) in verse 6 indicate about the nature of the visitor?', 'The appearance of the angel had overwhelming divine majesty that inspired reverential awe, suggesting a theophany rather than an ordinary angelic visit', 'The angel was physically frightening in a demonic sense', 'The woman was simply afraid of strangers', 'The angel was wearing battle armour', 'a', 'Judges 13:6 — "a man of God came unto me, and his countenance was like the countenance of an angel of God, very terrible." The combination with the secret name and the flame ascent in verse 20 has led many interpreters to identify this as the Angel of the LORD — a pre-incarnate appearance of Christ.'),
('Judges', 13, 'adults', 3, 'How does the Nazirite vow prescribed for Samson in Judges 13 differ from the voluntary Nazirite vow described in Numbers 6?', 'Samson''s vow was lifelong and imposed from the womb by divine decree; Numbers 6 describes a voluntary, temporary vow that an individual chooses', 'Samson''s vow was identical to Numbers 6 in every respect', 'Numbers 6 also permits lifelong Nazirites from birth', 'Samson''s vow was given by a priest, not an angel', 'a', 'Judges 13:5 — "the child shall be a Nazarite unto God from the womb to the day of his death." Numbers 6:2-5 describes an individual voluntarily consecrating themselves for a defined period.'),
('Judges', 13, 'adults', 4, 'What does the angel''s refusal to eat food in Judges 13:16 suggest about the nature of the messenger?', 'It indicates a transcendent, non-corporeal being not requiring sustenance — contrasting with angels in Genesis 18-19 who ate with Abraham and Lot', 'Angels always refuse human food in the Bible', 'The angel was following a fast as part of his mission', 'It was a test of Manoah''s generosity', 'a', 'Judges 13:16 — "And the angel of the LORD said unto Manoah, Though thou detain me, I will not eat of thy bread." Genesis 18:8 depicts angels eating with Abraham. The contrast raises deep questions about angelology and theophany in the Hebrew Bible.'),
('Judges', 13, 'adults', 5, 'What is the narrative irony of Israel being oppressed by the Philistines when Samson is announced as deliverer in Judges 13:5?', 'The announcement declares "he shall begin to deliver Israel," implying Samson''s deliverance will be incomplete — a deliberate narrative foreshadowing of the paradoxical and flawed nature of his judgeship', 'The Philistine oppression had already ended when Samson was born', 'Samson was destined to fully and finally defeat Philistia', 'The word "begin" means "completely accomplish" in Hebrew', 'a', 'Judges 13:5 — "he shall begin to deliver Israel out of the hand of the Philistines." The word "begin" is significant — Israel was not fully delivered from Philistia until Samuel''s time (1 Sam. 7), showing Samson only initiates a longer process.'),
('Judges', 13, 'adults', 6, 'What does Manoah''s wife''s reassurance to her husband in verses 22-23 reveal about her theological insight compared to his?', 'She displayed greater theological reasoning: God would not have accepted their sacrifice and shown them these things if He intended to kill them', 'She was simply trying to calm his emotions without theological substance', 'Manoah was right to be afraid and her reassurance was naive', 'Her argument was borrowed from pagan religious reasoning', 'a', 'Judges 13:23 — "But his wife said unto him, If the LORD were pleased to kill us, he would not have received a burnt offering and a meat offering at our hands." Her argument from divine consistency and grace is theologically astute.'),
('Judges', 13, 'adults', 7, 'How does Judges 13 function as a literary counterpart to Judges 16, and what does the contrast reveal?', 'Chapter 13 shows Samson''s life beginning with divine glory — miraculous birth, angelic announcement, Nazirite consecration; chapter 16 shows the squandering of that gift through sin, reversing every element', 'Chapter 13 focuses on his mother; chapter 16 focuses on his father', 'Both chapters show Samson at his spiritual best', 'The two chapters are from different literary sources with no intended connection', 'a', 'Judges 13:24-25 — "And the woman bare a son, and called his name Samson: and the child grew, and the LORD blessed him. And the Spirit of the LORD began to move him." The glorious beginning makes the catastrophic end of chapter 16 all the more tragic.'),
('Judges', 13, 'adults', 8, 'What does the phrase "the Spirit of the LORD began to move him at times in the camp of Dan" in verse 25 suggest about the nature of Samson''s supernatural strength?', 'It was episodic and Spirit-given, not an intrinsic physical quality — implying his strength was always a divine gift that could be withdrawn', 'He was naturally the strongest man alive and the Spirit enhanced that strength', 'The Spirit moved him only in the tribe of Dan and nowhere else', 'The movement of the Spirit referred to prophetic visions, not physical strength', 'a', 'Judges 13:25 — "And the Spirit of the LORD began to move him at times." The phrase "at times" and "began to move" indicates intermittent, Spirit-driven empowerment, which makes his later loss of strength when the Spirit departs (Judges 16:20) theologically coherent.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 14, 'teens', 1, 'What was Samson''s riddle at the wedding feast?', '"Out of the eater came forth meat, and out of the strong came forth sweetness"', '"A lion ate honey yet lived; how can this be?"', '"That which I killed gave me life; that which was dead gave sweetness"', '"Strong and sweet in the same house; what is it?"', 'a', 'Judges 14:14 — "And he said unto them, Out of the eater came forth meat, and out of the strong came forth sweetness. And they could not in three days expound the riddle."'),
('Judges', 14, 'teens', 2, 'How did the Philistine companions persuade Samson''s wife to get the answer to the riddle?', 'They threatened to burn her and her father''s house with fire', 'They offered her silver and gold', 'They promised to make her husband king', 'They threatened to report her father to the Philistine rulers', 'a', 'Judges 14:15 — "And it came to pass on the seventh day, that they said unto Samson''s wife, Entice thy husband, that he may declare unto us the riddle, lest we burn thee and thy father''s house with fire."'),
('Judges', 14, 'teens', 3, 'Where did Samson go to get the thirty changes of garments to pay his debt after they answered the riddle?', 'He went to Ashkelon and slew thirty Philistines and took their spoil', 'He went to Shiloh and took temple garments', 'He went back to his father''s house to collect them', 'He demanded them from the wedding guests', 'a', 'Judges 14:19 — "And the Spirit of the LORD came upon him, and he went down to Ashkelon, and slew thirty men of them, and took their spoil."'),
('Judges', 14, 'teens', 4, 'What happened to Samson''s Philistine wife after he departed in anger?', 'She was given to his companion who had been his best man', 'She was sent back to her father''s house alone', 'She fled to Israel to find Samson', 'She was executed for revealing the riddle', 'a', 'Judges 14:20 — "But Samson''s wife was given to his companion, whom he had used as his friend." This betrayal became the seed of further conflict in chapter 15.'),
('Judges', 14, 'teens', 5, 'What was God''s hidden purpose behind Samson''s desire to marry a Philistine woman?', 'God was seeking an occasion against the Philistines', 'God was testing Samson''s faithfulness', 'God wanted Samson to convert the Philistines', 'God was fulfilling a covenant with the tribe of Dan', 'a', 'Judges 14:4 — "But his father and his mother knew not that it was of the LORD, that he sought an occasion against the Philistines." God used even Samson''s fleshly desires as part of His sovereign plan.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 14, 'adults', 1, 'What Nazirite violation is implied by Samson eating honey from the lion''s carcass, and what does this signal about his character?', 'Contact with a dead animal carcass violated the Nazirite prohibition against touching anything dead (Numbers 6:6), revealing that Samson treated his consecration casually from early on', 'There is no Nazirite prohibition on honey from animals', 'The violation was forgiven because the honey was a gift from God', 'The lion was not technically dead at the moment Samson ate', 'a', 'Numbers 6:6 — "he shall come at no dead body." Judges 14:8-9 — Samson scooped honey from the lion''s carcass. This early, casual violation of his Nazirite vow foreshadows the tragic end of chapter 16.'),
('Judges', 14, 'adults', 2, 'What does the phrase "of the LORD" in Judges 14:4 introduce theologically, and how does it relate to the doctrine of divine providence?', 'It affirms that God can direct even sinful human desires toward His sovereign purposes without becoming the author of sin', 'It means God approved of marriage to Canaanite women', 'It means Samson was sinlessly obeying God by marrying a Philistine', 'It is a later editorial addition attempting to excuse Samson''s sin', 'a', 'Judges 14:4 — "it was of the LORD, that he sought an occasion against the Philistines." This is a key text for divine providence — God works through human passions and sinful choices without endorsing them, steering history toward His purposes.'),
('Judges', 14, 'adults', 3, 'What does the structure of Samson''s riddle — "eater/meat" and "strong/sweetness" — and his later explanation in Judges 14:18 reveal about his emotional state?', 'His counter-riddle "If ye had not plowed with my heifer" reveals deep personal betrayal — he experienced intimacy as violation, likening his wife to a farm animal exploited by others', 'His explanation was purely intellectual with no emotional content', 'His counter-riddle was a standard Philistine proverb he quoted', 'He was proud of solving the riddle himself and boasted of it', 'a', 'Judges 14:18 — "If ye had not plowed with my heifer, ye had not found out my riddle." The agricultural metaphor for sexual betrayal (heifer/plowing) is a raw expression of betrayal rather than a compliment to his wife.'),
('Judges', 14, 'adults', 4, 'How does Judges 14:19 present the Spirit of the LORD and violence together, and what theological tension does this create?', 'The Spirit empowers Samson to kill thirty men — raising the same tension as holy war texts: God''s Spirit authorising lethal violence as judicial punishment on Israel''s oppressors', 'The Spirit only moved Samson spiritually and had nothing to do with the killing', 'God condemned the killing even while the Spirit moved him', 'The violence was purely Samson''s own sin and the Spirit had already withdrawn', 'a', 'Judges 14:19 — "And the Spirit of the LORD came upon him, and he went down to Ashkelon, and slew thirty men." The Spirit''s involvement in violent deliverance connects to holy war theology in Deuteronomy 20 and the conquest narratives.'),
('Judges', 14, 'adults', 5, 'What does Samson''s parents'' objection to a Philistine marriage (v. 3) and his insistence reveal about the tension between parental authority and individual desire in the Mosaic law?', 'Deuteronomy 7:3 explicitly forbade intermarriage with Canaanites; Samson''s dismissal of his parents'' valid legal objection shows his characteristic disregard for covenant boundaries even as God sovereignly used the transgression', 'The Mosaic law had no provision about intermarriage with Philistines specifically', 'His parents were wrong to object because Philistines were not Canaanites under the law', 'His parents objected only for social, not religious, reasons', 'a', 'Judges 14:3 — "Is there never a woman among the daughters of thy brethren...that thou goest to take a wife of the uncircumcised Philistines?" Deuteronomy 7:3 prohibits such marriages specifically to prevent spiritual corruption.'),
('Judges', 14, 'adults', 6, 'What is the literary function of the honey-from-the-carcass episode as a symbol for Samson''s life and ministry?', 'It encapsulates his whole story — strength and sweetness emerging from death and uncleanness, just as his greatest victory (pulling down the temple) comes through his own death', 'It is only a test of cunning with no symbolic significance', 'It represents Israel''s ability to extract blessing from Canaanite culture', 'It symbolises the honey of the Promised Land obtained through warfare', 'a', 'Judges 14:14 — "Out of the eater came forth meat, and out of the strong came forth sweetness." The riddle becomes an unintended prophecy of Samson himself: a life of violence that paradoxically produces deliverance, culminating in death that saves Israel.'),
('Judges', 14, 'adults', 7, 'How many companions did the Philistines bring to the feast, and what does this detail suggest about the political atmosphere?', 'Thirty companions — a number suggesting a heavily armed guard rather than friendly guests, indicating the Philistines mistrusted Samson from the start', 'Ten companions who were simply wedding guests', 'Seven companions representing the days of the feast', 'A hundred companions as a sign of honour to Samson', 'a', 'Judges 14:11 — "And it came to pass, when they saw him, that they brought thirty companions to be with him." Many commentators note the unusually large number may indicate the Philistines sent these men as guards to watch this feared Israelite.'),
('Judges', 14, 'adults', 8, 'How does Samson''s wedding in Judges 14 foreshadow the relationship between Israel and the surrounding nations throughout the book of Judges?', 'Just as Samson''s marriage to a Philistine brings short-term pleasure but ends in betrayal and death, Israel''s repeated entanglement with pagan nations brought momentary alliance but culminated in oppression and spiritual destruction', 'Samson''s marriage was an exception and has no broader national application', 'The marriage ended happily and represents God''s desire for Israel to integrate with Canaan', 'It is only a personal story with no typological or national dimension', 'a', 'The cycle of attraction, betrayal, and destruction in Judges 14 mirrors the macro-narrative of Judges 2:1-3, where Israel''s entanglement with Canaanite nations leads to serving their gods and being oppressed by them.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 15, 'teens', 1, 'Why did the Philistines burn Samson''s wife and her father?', 'Because Samson had burned their fields and they blamed her for the trouble Samson brought', 'Because she had warned Samson of their plan', 'Because she refused to spy on Samson for them', 'Because she had run away to Israel', 'a', 'Judges 15:6 — "And the Philistines came up, and burnt her and her father with fire." They acted exactly as they had threatened in Judges 14:15, fulfilling Samson''s prediction that they only used her against him.'),
('Judges', 15, 'teens', 2, 'What did three thousand men of Judah do to Samson, and why?', 'They bound him with two new cords and delivered him to the Philistines, fearing Philistine retaliation', 'They sheltered him and refused to hand him over', 'They brought him to the tabernacle at Shiloh', 'They made him their leader to fight the Philistines', 'a', 'Judges 15:12-13 — "We are come down to bind thee, that we may deliver thee into the hand of the Philistines...And they bound him with two new cords." Judah prioritised peace with Philistia over defending a fellow Israelite.'),
('Judges', 15, 'teens', 3, 'What happened to Samson''s bonds when the Philistines came to take him?', 'The cords became like burnt flax and he broke free', 'He slipped out of the ropes like a snake shedding skin', 'An angel cut his bonds with a sword', 'The ropes rotted instantly on his wrists', 'a', 'Judges 15:14 — "the cords that were upon his arms became as flax that was burnt with fire, and his bands loosed from off his hands." The Spirit of the LORD empowered this supernatural breakout.'),
('Judges', 15, 'teens', 4, 'What did Samson name the place where he struck down the thousand Philistines?', 'Ramath-lehi, meaning "the hill of the jawbone"', 'Gibeah, meaning "the hill of battle"', 'Ebenezer, meaning "stone of help"', 'Bochim, meaning "the place of weeping"', 'a', 'Judges 15:17 — "And it came to pass, when he had made an end of speaking, that he cast away the jawbone out of his hand, and called that place Ramath-lehi." The name commemorates the weapon and the victory.'),
('Judges', 15, 'teens', 5, 'How many years did Samson judge Israel according to Judges 15:20?', 'Twenty years in the days of the Philistines', 'Forty years over all Israel', 'Twelve years over Judah only', 'Seven years from Zorah', 'a', 'Judges 15:20 — "And he judged Israel in the days of the Philistines twenty years." This summary statement closes the first major phase of Samson''s story.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 15, 'adults', 1, 'What does the Philistines'' burning of Samson''s wife and her father fulfill, and what does this reveal about the cyclical logic of vengeance in Judges 15?', 'It fulfills the Philistines'' own threat from Judges 14:15 and perpetuates a cycle where each act of revenge provokes a greater counter-act, escalating without covenant justice', 'It was an act of worship to their gods', 'It fulfills a specific prophecy from Deborah''s song', 'It was Samson''s fault for starting the cycle with the foxes', 'a', 'Judges 15:6-7 — The burning fulfills Judges 14:15; Samson''s response in 15:7 — "Though ye have done this, yet will I be avenged of you" — perpetuates the cycle. The narrative shows vengeance as an engine of escalating violence without resolution.'),
('Judges', 15, 'adults', 2, 'What is the theological significance of three thousand men of Judah choosing to hand Samson to the Philistines rather than rally behind him?', 'It reveals that Israel had accepted servitude as normal, lacking the spiritual will to seek freedom — a symptom of the covenant abandonment the entire book diagnoses', 'It shows that Judah was morally superior to Dan in not provoking Philistia', 'It demonstrates that the men of Judah were following Mosaic law about surrendering criminals', 'Judah was simply afraid and had no deeper theological meaning', 'a', 'Judges 15:11 — "Knowest thou not that the Philistines are rulers over us? What is this that thou hast done unto us?" Judah''s acceptance of Philistine rule as normal marks a total collapse of the Exodus identity of freedom under God.'),
('Judges', 15, 'adults', 3, 'What does the miracle of water from the jawbone in Judges 15:18-19 reveal about Samson''s spiritual condition, and how does it compare to Israel''s wilderness experience?', 'Like Israel at Meribah, Samson''s thirst after victory was met by miraculous divine provision, but he named the spring with possessive language ("God hath given this deliverance into the hand of thy servant") suggesting self-focus even in prayer', 'Samson was spiritually mature and the miracle was simply a physical provision', 'The miracle shows God no longer needed Samson after the battle', 'The comparison with the wilderness is the author''s own invention with no textual basis', 'a', 'Judges 15:18 — "Then he was sore athirst, and called on the LORD, and said, Thou hast given this great deliverance into the hand of thy servant." Compare Exodus 17:3-7 where God provided water after battle. Samson cried to God only in extremity, unlike Moses who interceded on behalf of the people.'),
('Judges', 15, 'adults', 4, 'What is the literary irony of the jawbone of an ass — an unclean animal — being the instrument of divine deliverance?', 'God consistently uses the weak, the despised, and the ritually impure as instruments of His power, confounding human expectations of what is fitting', 'The jawbone was a common weapon in antiquity and there is nothing unusual about its use', 'The use of an unclean item was a deliberate sin that God later punished Samson for', 'God blessed the weapon because Samson consecrated it before the battle', 'a', 'Judges 15:15 — "And he found a new jawbone of an ass...and slew a thousand men therewith." An ass was unclean under Levitical law, yet God empowered its bones as a weapon. This anticipates Paul''s "God hath chosen the weak things of the world to confound the things which are mighty" (1 Cor. 1:27).'),
('Judges', 15, 'adults', 5, 'How does Samson''s speech in Judges 15:16 function as a poetic victory song, and what is its literary form?', 'It is a brief victory boast in parallelism: "With the jawbone of an ass, heaps upon heaps" — with a wordplay on "chamor" (ass) and "chamar" (heap) — resembling ancient Near Eastern victory poetry', 'It is a simple prosaic statement with no poetic features', 'It is a prayer of thanksgiving directed entirely to God', 'It is a formal legal declaration claiming the land for Israel', 'a', 'Judges 15:16 — "With the jawbone of an ass, heaps upon heaps, with the jaw of an ass have I slain a thousand men." The repetition and the probable Hebrew wordplay make this a formulaic victory boast comparable to Lamech''s sword song (Gen. 4:23-24).'),
('Judges', 15, 'adults', 6, 'What does Samson''s naming the spring "En-hakkore" ("the spring of one who called") reveal about his understanding of his own power?', 'He attributed the water miracle to God''s answer to his cry, showing he knew his strength was divine gift not personal possession — though he did not consistently live this out', 'He named it after himself in pride', 'He was giving credit to the jawbone that provided water', 'The name indicates he thought his own call was the source of power', 'a', 'Judges 15:19 — "Wherefore he called the name thereof En-hakkore, which is in Lehi unto this day." The name "the spring of him that called" credits God''s response to prayer, preserving a moment of genuine dependence amid Samson''s generally self-reliant pattern.'),
('Judges', 15, 'adults', 7, 'How does the placement of the summary formula in Judges 15:20 — "he judged Israel twenty years" — in the middle of the Samson narrative rather than at the end affect interpretation?', 'It creates a narrative pause before chapter 16''s catastrophe, suggesting a period of relative stability before the final tragic arc — implying Samson''s story is not simply a linear decline', 'It is an editorial error that should appear at the end of chapter 16', 'It means chapter 16 is not part of the original Samson narrative', 'It summarises all of Samson''s activity before chapter 16 begins a new story about a different person', 'a', 'Judges 15:20 and 16:31 both include the same summary formula. The repetition creates a literary frame for the Delilah episode, marking it as a separate but climactic phase of Samson''s judgeship.'),
('Judges', 15, 'adults', 8, 'What does the word "Etam" (a rock cleft where Samson dwelt, v. 8) contribute to the geography of his story?', 'It places Samson in Judah''s territory, showing the judge of Dan was hiding in a neighbouring tribe''s land — suggesting Dan had been so absorbed into Philistine control that even its judge had no secure base', 'Etam was Samson''s hometown in the tribe of Dan', 'Etam was a Philistine city that Samson had captured', 'Etam was the location of the tabernacle during this period', 'a', 'Judges 15:8 — "he went down and dwelt in the top of the rock Etam." Etam is in Judahite territory. Samson, judge of Dan, was effectively a fugitive in Judah, underlining how badly the Philistine occupation had displaced northern tribal life.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 16, 'teens', 1, 'How much silver did each lord of the Philistines offer Delilah to betray Samson?', 'Eleven hundred pieces of silver', 'Five hundred pieces of silver', 'A thousand pieces of silver', 'Two hundred pieces of silver', 'a', 'Judges 16:5 — "I will give thee every one of us eleven hundred pieces of silver." With five lords, the total amounted to 5,500 pieces of silver.'),
('Judges', 16, 'teens', 2, 'How many false answers did Samson give Delilah before finally telling the truth about his hair?', 'Three false answers before the truth', 'One false answer', 'Five false answers', 'He never gave a false answer', 'a', 'Judges 16:7,11,13 — Samson first said seven green withes, then new ropes, then weaving his hair into a web. Each time he was tested and escaped, yet he told Delilah more truth each time, showing a tragic pattern of progressive disclosure.'),
('Judges', 16, 'teens', 3, 'What two things did the Philistines do to Samson after shaving his head and capturing him?', 'They put out his eyes and brought him down to Gaza', 'They chained him and paraded him through Philistine cities', 'They cut off his hands and displayed him in Ashdod', 'They bound him and sacrificed him to Dagon', 'a', 'Judges 16:21 — "But the Philistines took him, and put out his eyes, and brought him down to Gaza, and bound him with fetters of brass; and he did grind in the prison house."'),
('Judges', 16, 'teens', 4, 'What was the name of the false god to whom the Philistines gave credit for delivering Samson into their hands?', 'Dagon', 'Baal', 'Chemosh', 'Molech', 'a', 'Judges 16:23 — "Then the lords of the Philistines gathered them together for to offer a great sacrifice unto Dagon their god, and to rejoice: for they said, Our god hath delivered Samson our enemy into our hand."'),
('Judges', 16, 'teens', 5, 'What was Samson''s final prayer before pulling down the pillars?', '"O Lord GOD, remember me, I pray thee, and strengthen me, I pray thee, only this once, O God"', '"Let me die with the Philistines and avenge my two eyes"', '"LORD God of Israel, grant me one last miracle for Thy glory"', '"O God, forgive my sin and restore me to Thy presence"', 'a', 'Judges 16:28 — "And Samson called unto the LORD, and said, O Lord GOD, remember me, I pray thee, and strengthen me, I pray thee, only this once, O God, that I may be at once avenged of the Philistines for my two eyes."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 16, 'adults', 1, 'What does the three-part structure of Delilah''s deceptions — each time Samson woke and broke free — suggest about his psychology?', 'His repeated return to Delilah after each betrayal shows a compulsive pattern of self-destruction, where he knew she was dangerous yet could not break free — a picture of sin''s enslaving nature', 'He was testing Delilah to see if she could be trusted', 'He was bound by Nazirite law not to abandon a woman he had pledged to', 'He did not realise Delilah was working for the Philistines until the fourth attempt', 'a', 'Judges 16:15-16 — "And she said unto him, How canst thou say, I love thee, when thine heart is not with me? thou hast mocked me these three times...And it came to pass, when she pressed him daily with her words, and urged him, so that his soul was vexed unto death." He knew yet stayed.'),
('Judges', 16, 'adults', 2, 'What is the theological weight of the phrase "And he wist not that the LORD was departed from him" in verse 20?', 'It is one of Scripture''s most haunting statements — he had so normalised the Lord''s presence as background support that its withdrawal went unnoticed, revealing the spiritual blindness that preceded the physical blindness', 'It means God had never truly been with Samson', 'It means Samson was unconscious when the LORD left', 'It is a narrative aside with no deeper theological meaning', 'a', 'Judges 16:20 — "And she said, The Philistines be upon thee, Samson. And he awoke out of his sleep, and said, I will go out as at other times before, and shake myself. And he wist not that the LORD was departed from him." This verse is the spiritual climax of the Samson narrative.'),
('Judges', 16, 'adults', 3, 'What is the significance of Samson grinding at the mill in the prison house of Gaza?', 'Grinding grain was women''s work and the most degrading labour in antiquity; his humiliation reverses every marker of his mighty identity — he who tore lions now grinds like a slave woman', 'It was a sign that Samson was being rehabilitated by the Philistines', 'Grinding was reserved for prisoners of war as honourable labour', 'He chose this task voluntarily as a sign of repentance', 'a', 'Judges 16:21 — "and he did grind in the prison house." The imagery of the mighty judge reduced to slave labour resonates with Isaiah 47:2 where grinding is an image of complete humiliation.'),
('Judges', 16, 'adults', 4, 'How does the narrative detail that Samson''s hair began to grow again in verse 22 function as a theological signal?', 'It signals the possibility of renewed consecration and divine grace — the vow was being restored even before Samson''s final prayer, suggesting grace precedes the sinner''s petition', 'It is only a biological fact with no spiritual meaning', 'It shows that Samson''s strength was purely physical and automatic', 'It means the Nazirite vow could not permanently be broken', 'a', 'Judges 16:22 — "Howbeit the hair of his head began to grow again after he was shaven." The placement of this verse before the feast of Dagon and Samson''s final prayer suggests the narrator intends the reader to see grace already moving toward restoration.'),
('Judges', 16, 'adults', 5, 'What is the typological significance many see in Samson''s death — dying with outstretched arms between two pillars to destroy God''s enemies?', 'It is seen as a type of Christ dying on the cross with arms outstretched, destroying the power of the enemy through death, killing more in dying than in all his life', 'There is no typological connection and the comparison is theologically unsound', 'It typifies the defeat of Israel by Philistia', 'It typifies Moses lifting his arms at the battle of Amalek', 'a', 'Judges 16:30 — "So the dead which he slew at his death were more than they which he slew in his life." Many patristic and Reformation commentators saw Samson''s death between the pillars as a type of Christ''s atoning death.'),
('Judges', 16, 'adults', 6, 'What does Judges 16 reveal about the spiritual condition of Israel that its judge is the prisoner of its oppressors, grinding in their prison, before his final act of deliverance?', 'It concretises the spiritual reality of Judges 2: Israel had become enslaved through covenant infidelity, and even its judge bore the marks of that slavery, making his final act a compressed picture of Israel''s own need for redemption', 'It is simply a personal failure of Samson with no national symbolism', 'It shows that the Philistines were spiritually superior to Israel at this time', 'It fulfills the curse of Deuteronomy 28 on Samson alone, not on all Israel', 'a', 'Judges 16:21 — Samson blinded, bound, grinding. Deuteronomy 28:29,33 warns that covenant apostasy would result in groping in darkness and serving enemies. Samson''s condition embodied the national spiritual state.'),
('Judges', 16, 'adults', 7, 'How does Delilah function narratively as a parallel to Samson''s Timnite wife in chapter 14?', 'Both women are non-Israelite, both press Samson with words until he tells them his secret, both betray him to Philistine enemies, and both receive the Philistines'' reward — showing Samson learned nothing from the first betrayal', 'Delilah was an Israelite woman, making the parallel impossible', 'The Timnite wife acted under threat while Delilah acted freely, making them opposites', 'There is no intentional parallel; the similar structure is coincidental', 'a', 'Judges 14:17 and 16:16 use parallel language of women pressing and urging Samson "daily" until "his soul was vexed unto death." The literary parallel is clearly intentional, emphasising Samson''s failure to learn from past betrayal.'),
('Judges', 16, 'adults', 8, 'What does the fact that Samson killed more Philistines at his death than in his life (v. 30) say about the theme of divine reversal in the book of Judges?', 'God''s greatest victories often come through apparent defeat and weakness — the blind, imprisoned, mocked deliverer accomplishes more in death than in the height of his power, anticipating the pattern of the Suffering Servant', 'Samson was simply more motivated by personal revenge than by duty', 'It means God rewards those who die in battle more than those who live', 'It is a numerical exaggeration common to ancient heroic literature with no theological weight', 'a', 'Judges 16:30 — "the dead which he slew at his death were more than they which he slew in his life." This reversal — strength through weakness, victory through death — is one of Scripture''s recurring patterns, culminating in Christ''s cross.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 17, 'teens', 1, 'How much silver was originally stolen from Micah''s mother, and what happened to it?', 'Eleven hundred shekels; Micah had stolen it, confessed when she cursed the thief, and returned it', 'Five hundred shekels; a servant stole it and was discovered', 'Two hundred shekels; it was lost in battle and later found', 'A thousand shekels; Micah borrowed it and forgot to repay it', 'a', 'Judges 17:2-3 — "The eleven hundred shekels of silver that were taken from thee...I took it. And his mother said, Blessed be thou of the LORD, my son. And when he had restored the eleven hundred shekels of silver to his mother, his mother said, I had wholly dedicated the silver unto the LORD from my hand for my son."'),
('Judges', 17, 'teens', 2, 'Where was the young Levite who became Micah''s priest originally from?', 'Beth-lehem-judah', 'Shiloh in Ephraim', 'Hebron in Judah', 'Beersheba in the Negev', 'a', 'Judges 17:7-8 — "And there was a young man out of Beth-lehem-judah of the family of Judah, who was a Levite, and he sojourned there. And the man departed out of the city from Beth-lehem-judah to sojourn where he could find a place."'),
('Judges', 17, 'teens', 3, 'What wages did Micah offer the Levite to serve as his personal priest?', 'Ten shekels of silver per year, a suit of apparel, and his victuals', 'Free housing and all his food', 'Twenty shekels per month plus animals for sacrifice', 'A portion of all offerings brought to the shrine', 'a', 'Judges 17:10 — "And Micah said unto him, Dwell with me, and be unto me a father and a priest, and I will give thee ten shekels of silver by the year, and a suit of apparel, and thy victuals."'),
('Judges', 17, 'teens', 4, 'Why was Micah pleased that the Levite agreed to become his priest?', 'He believed the LORD would do him good because he had a Levite as priest', 'He thought the Levite had special magical powers', 'He wanted to impress the other tribes of Israel', 'He needed someone to read the law to him', 'a', 'Judges 17:13 — "Then said Micah, Now know I that the LORD will do me good, seeing I have a Levite to my priest." This shows his syncretistic thinking — mixing idol worship with the prestige of legitimate Levitical lineage.'),
('Judges', 17, 'teens', 5, 'What objects besides the idol did Micah place in his shrine?', 'An ephod and teraphim', 'A golden calf and an asherah pole', 'A bronze serpent and the ark''s replica', 'Twelve stones and an altar of burnt offering', 'a', 'Judges 17:5 — "And the man Micah had an house of gods, and made an ephod, and teraphim, and consecrated one of his sons, who became his priest." An ephod was a priestly garment; teraphim were household idols.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 17, 'adults', 1, 'What is the theological irony in Micah''s mother dedicating the silver "wholly unto the LORD" while simultaneously commissioning a graven image with it?', 'She used explicitly sacred language of covenant dedication to finance the manufacture of an idol — combining the LORD''s name with the very idolatry He forbids, the essence of syncretism', 'She was ignorant of the second commandment and acted in good faith', 'The silver was only partially used for an idol; the rest went to the tabernacle', 'Her dedication was sincere and the image was not an idol in her understanding', 'a', 'Judges 17:3 — "I had wholly dedicated the silver unto the LORD from my hand for my son, to make a graven image and a molten image." Exodus 20:4 forbids graven images. She invokes the LORD''s name while disobeying His explicit command — a portrait of popular religion''s corruption.'),
('Judges', 17, 'adults', 2, 'What does the theft of silver from one''s own mother and the subsequent curse reveal about the moral climate of the household in Judges 17:2?', 'Family relationships and basic moral constraints had broken down — a microcosm of the social dissolution the book diagnoses nationally', 'Theft within families was common and legally acceptable in ancient Israel', 'Micah was unusually wicked compared to his generation', 'The curse his mother pronounced had no moral weight in Israelite culture', 'a', 'Judges 17:2 — "And he said unto his mother...I took it." The casual admission and the mother''s blessing immediately after suggests the collapse of moral order even within the household, reflecting the "every man for himself" refrain of verse 6.'),
('Judges', 17, 'adults', 3, 'What does Micah''s hiring of a Levite "like a father and a priest" reveal about how Israel''s religious institutions had been corrupted?', 'The Levitical office had become a commodity for hire by private individuals, detached from the Mosaic system of tabernacle service — priesthood had become a personal career rather than a covenant calling', 'The Levite was doing precisely what Mosaic law allowed', 'Micah was following legitimate precedent established by earlier judges', 'Levites were permitted under the law to serve private households as supplementary priests', 'a', 'Judges 17:10-12 — "I will give thee ten shekels of silver by the year...And the Levite was content to dwell with the man." Numbers 18:1-7 assigned Levites to tabernacle service. Micah''s arrangement was a privatisation of sacred office.'),
('Judges', 17, 'adults', 4, 'How does Judges 17 function as the beginning of a two-part appendix (chapters 17-21) that differs structurally from the main body of the book?', 'Chapters 17-21 lack the standard judge-cycle formula (sin/oppression/cry/deliverance) and instead provide direct narrative illustrations of social and religious collapse — functioning as an epilogue that explains why the cycle ended in chaos', 'Chapters 17-21 are a separate literary work accidentally attached to Judges', 'The epilogue shows the period was actually spiritually better than the main narrative suggests', 'The two appendices focus on military history rather than religious themes', 'a', 'Scholars widely recognise that Judges 17-21 lacks the Deuteronomistic formulaic framework of chapters 1-16. The absence of judges, oppressors, and deliverance shifts the mode from cyclical narrative to diagnostic illustration of covenant collapse.'),
('Judges', 17, 'adults', 5, 'What does Micah''s statement "Now know I that the LORD will do me good, seeing I have a Levite to my priest" reveal about a dangerous theology?', 'He believed he could manufacture divine blessing by securing the right religious personnel and objects — a transactional, magical view of religion that substitutes ritual for obedience', 'His statement shows genuine faith in God''s covenant faithfulness', 'Having a Levite priest was itself a sign of God''s blessing with no problematic assumptions', 'He was correct because God did bless him for his generosity', 'a', 'Judges 17:13 — "Now know I that the LORD will do me good." This reflects a magical-transactional theology: the right priest + right ritual objects = guaranteed blessing, regardless of whether the entire enterprise violates the law. This is the opposite of the prophetic ethic.'),
('Judges', 17, 'adults', 6, 'How does the refrain "there was no king in Israel" in verse 6 function as both a historical observation and a theological argument?', 'It argues that the chaos documented in chapters 17-21 was caused not merely by the absence of human government but by the nation''s rejection of the LORD''s kingship — and anticipates both the monarchy''s establishment and its own failure to solve the deeper problem', 'It is simply a historical note explaining the political vacuum', 'It argues monarchy would have prevented all the sins described', 'It means the Davidic covenant had not yet been promised to Israel', 'a', 'Judges 17:6 — "every man did that which was right in his own eyes." The refrain appears four times (17:6; 18:1; 19:1; 21:25). It frames the epilogue as a diagnosis of covenant autonomy — Israel acting as sovereign over itself rather than living under God''s kingship.'),
('Judges', 17, 'adults', 7, 'What specific commandments are being violated in Judges 17, and how does this chapter serve as a catalogue of the second table?', 'The chapter illustrates violations of the first and second commandments (idolatry, graven image), the fifth (son stealing from mother), the eighth (theft), and the second commandment''s prohibition on using God''s name to sanctify idolatry', 'Only one commandment is broken — the prohibition on graven images', 'The Mosaic law had not yet been given in written form during the judges period', 'The chapter shows commandments being kept correctly', 'a', 'Judges 17:2-5 — theft (8th commandment), false use of God''s name (3rd), graven image (2nd), idolatry (1st). The chapter is a remarkable compressed illustration of covenant breakdown across the Decalogue''s opening commandments.'),
('Judges', 17, 'adults', 8, 'What does the word "teraphim" indicate about the theological syncretism occurring in Micah''s shrine?', 'Teraphim were household gods used for divination, well-documented in Mesopotamian and Canaanite cultures — their presence in a shrine dedicated to the LORD shows direct borrowing of pagan practice under the surface of Israelite religion', 'Teraphim were legitimate instruments of worship approved by Moses', 'They were architectural decorations with no religious function', 'Teraphim were only used by foreign nations and were never present in Israel''s religious life', 'a', 'Judges 17:5 — "he made an ephod, and teraphim." Teraphim appear also in Genesis 31:19 (Rachel''s household gods), 1 Samuel 19:13, and Ezekiel 21:21 as divination tools. Their presence alongside an ephod represents the blending of legitimate Israelite symbols with Canaanite household religion.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 18, 'teens', 1, 'What was the Levite''s response when the Danites invited him to be priest for a whole tribe rather than one household?', 'He agreed immediately, saying it was better to be a priest for a tribe than for one man''s house', 'He refused out of loyalty to Micah', 'He consulted the LORD through the Urim and Thummim first', 'He agreed only after the tribe paid him double his wages from Micah', 'a', 'Judges 18:19-20 — "And they said unto him, Hold thy peace, lay thine hand upon thy mouth, and go with us...And the priest''s heart was glad; and he took the ephod, and the teraphim, and the graven image, and went in the midst of the people."'),
('Judges', 18, 'teens', 2, 'How many spies did the Danites send ahead to search out the land before the main force marched?', 'Five men', 'Twelve men like Joshua''s spies', 'Two men', 'Seven men', 'a', 'Judges 18:2 — "And the children of Dan sent of their family five men from their coasts, men of valour, from Zorah, and from Eshtaol, to spy out the land, and to search it."'),
('Judges', 18, 'teens', 3, 'What oracle did the Levite give the five Danite spies when they asked about their journey?', '"Before the LORD is your way wherein ye go"', '"Go in peace and the LORD will bless your quest"', '"Your journey shall not prosper; turn back"', '"The LORD has not sent me to answer you"', 'a', 'Judges 18:6 — "And the priest said unto them, Go in peace: before the LORD is your way wherein ye go." He gave a favourable oracle despite serving at an idolatrous shrine.'),
('Judges', 18, 'teens', 4, 'What was the condition of the people of Laish (which Dan conquered) that made them easy to defeat?', 'They were quiet and secure, with no connection to any neighbouring people, and had no deliverer', 'They had a large army but poor weapons', 'They had been weakened by a recent plague', 'They were allied with the Philistines but those allies never came', 'a', 'Judges 18:7,28 — "And the five men...saw the people that were therein, how they dwelt careless, after the manner of the Zidonians...and there was no deliverer, because it was far from Zidon, and they had no business with any man."'),
('Judges', 18, 'teens', 5, 'When Micah chased after the Danites to reclaim his idols, what did they say to discourage him?', 'That he was outnumbered and they would kill him and his household if he persisted', 'That his idols were false and worthless anyway', 'That the Levite had given them the idols willingly', 'That the LORD had told them to take the idols', 'a', 'Judges 18:25 — "And the children of Dan said unto him, Let not thy voice be heard among us, lest angry fellows run upon thee, and thou lose thy life, with the lives of thy household." Micah turned and went home, recognising he was helpless.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 18, 'adults', 1, 'What is the theological scandal of the statement in Judges 18:30 that Jonathan son of Gershom son of Manasseh served as priest of Dan''s idolatrous shrine?', 'Several manuscripts read "Moses" not "Manasseh" (with a suspended nun), meaning the grandson of Moses himself served as priest of an idolatrous cult — the ultimate irony of Israel''s first lawgiver''s family leading apostate worship', 'Jonathan was an obscure Levite with no notable ancestry', 'The name Manasseh refers to the half-tribe, not Moses', 'The text clearly reads Manasseh and has no connection to Moses', 'a', 'Judges 18:30 — "And Jonathan, the son of Gershom, the son of Manasseh, he and his sons were priests to the tribe of Dan." The Masoretic scribes inserted a "nun" to change "Moses" to "Manasseh" to protect Moses'' reputation, but many scholars and the LXX suggest the original reading was "Moses."'),
('Judges', 18, 'adults', 2, 'What does the Danite migration narrative reveal about the failure of the tribal allotment system described in Joshua 19?', 'Dan was originally allotted territory in the coastal plain but could not drive out the Amorites (Judges 1:34), forcing a northern migration — showing that the promises of Joshua 19 required obedient military engagement that Dan failed to perform', 'Dan simply preferred the north and chose to migrate voluntarily', 'The Joshua allotment never assigned Dan any territory at all', 'Dan''s migration was a blessing because their original territory was inferior', 'a', 'Judges 1:34 — "And the Amorites forced the children of Dan into the mountain: for they would not suffer them to come down to the valley." The migration in Judges 18 is the long-term consequence of Judges 1''s failure to take the land.'),
('Judges', 18, 'adults', 3, 'How does the Danite theft of Micah''s idol demonstrate the principle that false religion is ultimately self-contradictory?', 'The idol that was supposed to guarantee blessing for Micah''s household was powerless to protect itself from theft — revealing that an object that cannot save itself cannot save its worshippers', 'The theft was a divine judgment on Micah''s idolatry using the Danites as instruments', 'The Danites were right to take the idol since a larger community deserved it more', 'The idol had no power either for Micah or for Dan, but for different reasons', 'a', 'Judges 18:24 — "And he said, Ye have taken away my gods which I made, and the priest, and ye are gone away." An idol that can be stolen is no god. The narrative ironically exposes the futility of idol worship through the mechanics of the story itself.'),
('Judges', 18, 'adults', 4, 'What does the Levite''s willingness to upgrade his employment from one household to one tribe reveal about his character and the corruption of the priestly office in this period?', 'He treated the sacred office as a career ladder — moving from Micah to Dan for greater status and presumably greater pay — revealing that priestly vocation had been replaced by priestly ambition', 'He acted with godly wisdom in seeking to serve a larger community', 'His move was theologically defensible because the tribe was a more legitimate authority', 'He was obeying the Levitical law about serving the congregational assembly rather than individuals', 'a', 'Judges 18:19-20 — "And the priest''s heart was glad." There is no prayer, no consultation, no hesitation — only eagerness for advancement. His gladness of heart at the promotion indicts the commercialisation of sacred office.'),
('Judges', 18, 'adults', 5, 'How does the description of Laish as "quiet and secure" and "careless" foreshadow a prophetic theme about complacent nations ripe for judgment?', 'It echoes Amos 6:1 "Woe to them that are at ease in Zion" and Ezekiel 16:49 on Sodom''s complacency — prosperity and isolation that give a false sense of security become vulnerabilities rather than protections', 'The description is purely military with no prophetic overtones', 'Laish''s carelessness was morally neutral and the Danites were wrong to attack', 'The "quiet and secure" language praises Laish as a model community', 'a', 'Judges 18:27 — "And they came unto Laish, unto a people that were at quiet and secure: and they smote them with the edge of the sword." The same language of false security appears in Jeremiah 49:31 about Kedar and Ezekiel 38:11 about Israel.'),
('Judges', 18, 'adults', 6, 'What does the establishment of the idolatrous shrine at Dan in Judges 18 prefigure in terms of the later history of the northern kingdom?', 'Jeroboam I erected one of his two golden calves at Dan (1 Kings 12:29), completing the pattern begun here — Dan became the northernmost centre of state idolatry in Israel, a trajectory begun in Judges 18', 'Dan eventually became the most faithful tribe in Israel, reversing the Judges 18 apostasy', 'The Dan shrine had no connection to Jeroboam''s later actions', 'Jeroboam built his shrine at Bethel, not at Dan, breaking the connection', 'a', '1 Kings 12:29-30 — "And he set the one in Beth-el, and the other put he in Dan. And this thing became a sin." The continuity between the Judges 18 idolatrous shrine at Dan and Jeroboam''s golden calf at Dan is one of Scripture''s deliberate historical echoes.'),
('Judges', 18, 'adults', 7, 'How does Micah''s helpless complaint "what have I more?" (v. 24) function as a tragic commentary on the nature of false religion?', 'When the idols are taken, he has nothing — his gods were the sum of his religious identity and security; when they go, his whole world collapses, revealing how utterly his hope was built on sand', 'His complaint shows legitimate grief at unjust theft that God would avenge', 'It reveals that Micah was secretly a faithful Israelite who only used idols for show', 'His statement is only about economic loss, not religious identity', 'a', 'Judges 18:24 — "And he said, Ye have taken away my gods which I made, and the priest, and ye are gone away: and what have I more?" The question "what have I more?" is both heartbreaking and self-condemning — his "more" was less than nothing.'),
('Judges', 18, 'adults', 8, 'What does the narrative phrase "all the time that the house of God was in Shiloh" in Judges 18:31 imply about the relationship between the Danite shrine and legitimate Israelite worship?', 'It runs the two institutions in parallel — the lawful tabernacle at Shiloh and the idolatrous shrine at Dan coexisted throughout this period, showing that apostasy did not replace true religion outright but ran alongside it in Israel''s religious life', 'It means the Shiloh tabernacle endorsed the Dan shrine', 'It proves the Shiloh tabernacle had already closed before Dan set up their shrine', 'It is a chronological note with no theological contrast intended', 'a', 'Judges 18:31 — "And they set them up Micah''s graven image...all the time that the house of God was in Shiloh." The parallel existence of the legitimate and the idolatrous is the religious tragedy of the period — syncretism coexisting with, not replacing, true worship.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 19, 'teens', 1, 'Why had the Levite''s concubine left him and returned to her father''s house?', 'She played the whore against him', 'She was sold to her father by the Levite', 'She was taken captive by Philistines on the road', 'She fell ill and returned home to be nursed back to health', 'a', 'Judges 19:2 — "And his concubine played the whore against him, and went away from him unto her father''s house to Beth-lehem-judah."'),
('Judges', 19, 'teens', 2, 'Why did the Levite choose to stay at Gibeah rather than the Jebusite city he had passed earlier?', 'He preferred not to lodge in a city of strangers who were not Israelites', 'The Jebusite city had no room for them', 'His donkeys were tired and could not go further', 'An angel warned him against entering the Jebusite city', 'a', 'Judges 19:12 — "And his master said unto him, We will not turn aside hither into the city of a stranger, that is not of the children of Israel; we will pass over to Gibeah." The irony is that the Israelite city proved far more dangerous than the foreign one.'),
('Judges', 19, 'teens', 3, 'What did the wicked men of Gibeah demand from the old man who had taken in the Levite?', 'That he bring out the man so they could sexually assault him', 'That he pay a fine for housing strangers without permission', 'That the Levite fight them in single combat', 'That the old man leave the city by morning', 'a', 'Judges 19:22 — "Now as they were making their hearts merry, behold, the men of the city, certain sons of Belial, beset the house round about...saying, Bring forth the man that came into thine house, that we may know him."'),
('Judges', 19, 'teens', 4, 'What did the Levite do with his concubine''s body when he found her dead at the doorstep?', 'He cut her body into twelve pieces and sent them throughout all Israel', 'He buried her with honour in Bethlehem', 'He carried her to Shiloh for a public burial', 'He left her body at the gate of Gibeah as a sign', 'a', 'Judges 19:29 — "And when he was come into his house, he took a knife, and laid hold on his concubine, and divided her, together with her bones, into twelve pieces, and sent her into all the coasts of Israel."'),
('Judges', 19, 'teens', 5, 'What words did the Levite use to call all Israel to attention when he sent the twelve pieces throughout the land?', '"Consider of it, take advice, and speak your minds"', '"Avenge the blood that has been shed in Israel"', '"Rise up and war against Benjamin for this evil deed"', '"The LORD requires justice for the innocent blood"', 'a', 'Judges 19:30 — "And it was so, that all that saw it said, There was no such deed done nor seen from the day that the children of Israel came up out of the land of Egypt unto this day: consider of it, take advice, and speak your minds."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 19, 'adults', 1, 'What literary parallel to Genesis 19 (Sodom) is present in Judges 19, and what is the theological point of the comparison?', 'Both narratives involve men demanding to sexually assault male guests, a host offering his daughter instead, the guest being sent outside, and the result being catastrophic judgment — the comparison implies Gibeah has become like Sodom, damning Benjamin by association', 'The two passages have surface similarities but no intended literary connection', 'The Genesis 19 parallel exonerates Gibeah because they did not receive divine fire', 'The only similarity is that both involve travel stories, not moral equivalence', 'a', 'Judges 19:22-25 parallels Genesis 19:1-9 almost exactly in structure and language. The Sodom comparison was intended by the author to signal that the covenant people had reached Sodomite depths of depravity — a verdict reinforced by the rest of the appendix.'),
('Judges', 19, 'adults', 2, 'What does the Levite''s delay of five days at his father-in-law''s house (vv. 1-9) contribute to the narrative thematically?', 'The extended delay creates a sense of domestic normalcy and hospitality that makes the subsequent horror at Gibeah all the more jarring — the contrast between genuine Middle Eastern hospitality at one house and its violent perversion at another is the narrative''s central moral axis', 'The delay is purely a chronological filler with no narrative purpose', 'It shows the father-in-law was trying to prevent the Levite from leaving with his daughter', 'It establishes that the Levite was lazy and irresponsible', 'a', 'Judges 19:4-9 — repeated generous hosting by the father-in-law ("comfort thine heart with a morsel of bread...thy father in law, the damsel''s father, said unto him, Comfort thine heart, I pray thee, and tarry all night") is placed in direct contrast with Gibeah''s complete failure of the same duty.'),
('Judges', 19, 'adults', 3, 'What is the moral complexity of the old man''s offer to give his virgin daughter and the concubine to the mob (v. 24)?', 'The offer attempts to protect the male guest under the absolute duty of hospitality but does so by treating women as expendable objects — it is both an act of desperate hospitality and a profound moral failure, showing how patriarchal culture''s blind spots were exploited by evil', 'The offer was righteous because protecting a male guest was the highest obligation in that culture', 'The old man was wicked and the text condemns him explicitly', 'The offer was never made; only the concubine was mentioned', 'a', 'Judges 19:24 — "Behold, here is my daughter a maiden, and his concubine; them I will bring out now, and humble ye them." The text does not editorially condemn the offer, but the narrative arc — the concubine''s death and the subsequent national horror — passes its own verdict.'),
('Judges', 19, 'adults', 4, 'What does the concubine''s position at the doorstep in verse 27 — hands on the threshold — suggest symbolically?', 'It is one of Scripture''s most poignant images: she had crawled back to the only place that offered any shelter, the threshold of her host''s door, and died there — representing the ultimate failure of Israel to protect its most vulnerable', 'She was resting and not actually dead when the Levite found her', 'The threshold position is a sign of ritual impurity that must be addressed before re-entering', 'She was placed there by the men of Gibeah as a deliberate insult to the Levite', 'a', 'Judges 19:27 — "And her lord rose up in the morning...and opened the doors of the house, and went out to go his way: and, behold, the woman his concubine was fallen down at the door of the house, and her hands were upon the threshold." The image is unbearably specific.'),
('Judges', 19, 'adults', 5, 'How does the Levite''s cold command "Rise up, and let us be going" in verse 28 characterise him morally, and what does his character add to the narrative''s indictment of Israel?', 'His callous response to finding his concubine dying or dead — no recorded grief, no lament, a pragmatic command — suggests the narrator intends the reader to see him as morally compromised, part of a system that uses and discards women', 'His command shows admirable self-control under extreme stress', 'The command is a sign he did not yet know she was dead', 'His response was culturally appropriate and should not be judged by modern standards', 'a', 'Judges 19:28 — "And he said unto her, Up, and let us be going. But none answered." No name, no lament, no tenderness is recorded. The narrative''s silence about his emotion is itself an indictment.'),
('Judges', 19, 'adults', 6, 'What is the significance of the Levite''s choice to cut the concubine''s body into twelve pieces corresponding to the twelve tribes?', 'It was a blood covenant summons modelled on Samuel''s later cutting of an ox (1 Sam. 11:7) — a ritual call to arms that invoked tribal solidarity and demanded corporate response to corporate shame', 'It was an act of madness by a traumatised man with no ritual significance', 'The twelve pieces represented a legal deposition of evidence against Benjamin', 'It was a form of Canaanite funeral practice adopted by the Levite', 'a', 'Judges 19:29 — "he...divided her, together with her bones, into twelve pieces." 1 Samuel 11:7 records Saul doing the same with oxen to summon Israel to battle. The parallel suggests the Levite was performing a recognised ritual summons to holy war.'),
('Judges', 19, 'adults', 7, 'How does Judges 19 function as the theological nadir of the entire book of Judges?', 'It represents the lowest point of the spiral: a Levite (a religious leader) is complicit in delivering his concubine to be killed; Benjamin (a tribe of Israel) replicates Sodom; and no one cries out to God — the name of God is entirely absent from the chapter', 'It is simply the worst historical event recorded in Judges without any broader theological function', 'The chapter represents a moral low point for Philistia, not Israel', 'The theological low point of Judges is Jephthah''s vow, not the Gibeah incident', 'a', 'Judges 19 does not mention the LORD in any active role. No one prays, no one invokes God''s name for help. The divine silence mirrors the spiritual vacuum that the entire epilogue has been documenting.'),
('Judges', 19, 'adults', 8, 'What does the communal response "there was no such deed done nor seen from the day that the children of Israel came up out of Egypt" reveal about the book''s overall argument?', 'The book of Judges argues that without covenant faithfulness to God, Israel deteriorates to a point lower than pagan nations — a total inversion of the Exodus project of forming a holy people distinct from surrounding cultures', 'It shows that Israel had always been righteous before Judges and the Gibeah incident was an isolated exception', 'The statement is hyperbole with no theological weight', 'It means the Gibeah incident was worse than the golden calf episode of Exodus 32', 'a', 'Judges 19:30 — "There was no such deed done nor seen from the day that the children of Israel came up out of the land of Egypt." The comparison to the Exodus marks the full collapse of the Exodus-covenant project. Israel has become what it was called out from Egypt to be distinct from.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 20, 'teens', 1, 'How many men did Israel assemble against Benjamin, and how many soldiers did Benjamin field?', 'Israel: four hundred thousand; Benjamin: twenty-six thousand seven hundred', 'Israel: two hundred thousand; Benjamin: ten thousand', 'Israel: three hundred thousand; Benjamin: thirty thousand', 'Israel: half a million; Benjamin: five thousand', 'a', 'Judges 20:17 — "And the men of Israel, beside Benjamin, were numbered four hundred thousand men that drew sword." Judges 20:15 — "twenty and six thousand men that drew sword...beside the inhabitants of Gibeah, which were numbered seven hundred chosen men."'),
('Judges', 20, 'teens', 2, 'What happened to Israel on the first two days of battle against Benjamin?', 'Israel was defeated both days, losing twenty-two thousand then eighteen thousand men', 'Israel won both days but with heavy casualties', 'The battle was a draw on both days', 'Benjamin retreated both days without fighting', 'a', 'Judges 20:21,25 — "And the children of Benjamin came forth...and destroyed down to the ground of the Israelites that day twenty and two thousand men...And Benjamin went forth against them the second day, and destroyed down to the ground of the children of Israel again eighteen thousand men."'),
('Judges', 20, 'teens', 3, 'Where did Israel go after their first two defeats, and what did they do there?', 'They went to Bethel and wept and fasted and offered burnt offerings and peace offerings before the LORD', 'They retreated to Shiloh and asked the high priest to consult the ephod', 'They went to Mizpeh and took a new oath of vengeance', 'They sent messengers to Joshua''s memorial at Gilgal to pray', 'a', 'Judges 20:26 — "Then all the children of Israel, and all the people, went up, and came unto the house of God, and wept, and sat there before the LORD, and fasted that day until even, and offered burnt offerings and peace offerings before the LORD."'),
('Judges', 20, 'teens', 4, 'What military ambush strategy did Israel use successfully on the third day of battle?', 'They set an ambush behind Gibeah while drawing Benjamin out of the city, then the ambush entered and burned the city', 'They attacked at night from three sides simultaneously', 'They dug trenches around Gibeah and starved Benjamin out', 'They used fire arrows to burn the crops and scatter the army', 'a', 'Judges 20:29-36 — "And Israel set liers in wait round about Gibeah...and the men of Israel went out of their place, and set themselves in array...and the liers in wait hasted, and rushed upon Gibeah; and the liers in wait drew themselves along, and smote all the city with the edge of the sword."'),
('Judges', 20, 'teens', 5, 'How many men of Benjamin survived the civil war by fleeing to the rock of Rimmon?', 'Six hundred men', 'A thousand men', 'Five thousand men', 'Two hundred men', 'a', 'Judges 20:47 — "But six hundred men turned and fled to the wilderness unto the rock Rimmon, and abode in the rock Rimmon four months."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 20, 'adults', 1, 'What is the theological paradox of Israel suffering two crushing defeats in the very war God told them to fight?', 'Israel asked God "who shall go up?" but not "shall we go up at all?" — their unexamined assumption that the war was just, combined with corporate sin and lack of genuine repentance, meant God allowed humiliation before granting victory', 'God never told Israel to fight Benjamin; they acted on their own', 'The defeats prove Israel was fighting unjustly and should have made peace', 'God was testing Benjamin rather than Israel, so Israel''s losses had no theological meaning', 'a', 'Judges 20:18 — "And the children of Israel arose, and went up to the house of God, and asked counsel of God, and said, Which of us shall go up first to the battle against the children of Benjamin?" They asked "who" not "whether" — presuming God''s sanction before obtaining it.'),
('Judges', 20, 'adults', 2, 'What does the detail that the Benjamite warriors included seven hundred left-handed slingers who could "sling stones at an hair breadth and not miss" contribute to the narrative?', 'It explains how a much smaller force inflicted massive casualties on two successive days — and it ironically recalls that Ehud, Israel''s earlier deliverer, was also a left-handed Benjamite (Judges 3:15), linking the tribe''s identity to ambidextrous warfare', 'It is a military curiosity with no broader narrative significance', 'It shows Benjamin was the most elite fighting force in Israel', 'The left-handed slingers were a Canaanite unit that had joined Benjamin', 'a', 'Judges 20:16 — "Among all this people there were seven hundred chosen men lefthanded; every one could sling stones at an hair breadth, and not miss." Judges 3:15 — "a man lefthanded" describes Ehud of Benjamin. The tribe''s tactical excellence is part of its characterisation across Judges.'),
('Judges', 20, 'adults', 3, 'What does the progression of Israel''s inquiries at Bethel across three days reveal about the development of their repentance?', 'Day 1 they asked only "who shall fight?" (no mention of prayer or fasting); after first defeat they wept and asked "shall we go again?" (some repentance); only after the second defeat did they fast, offer sacrifices, and genuinely lament before God — suggesting the earlier inquiries lacked true contrition', 'All three inquiries were identical in character and depth of repentance', 'God required Israel to fail twice as arbitrary punishment unrelated to their spiritual state', 'The three inquiries follow a set liturgical pattern with no spiritual progression', 'a', 'Judges 20:18,23,26-28 — the escalating response from a simple tactical question to full-blown lamentation, fasting, and sacrifice mirrors the standard pattern of genuine repentance seen throughout Israel''s history.'),
('Judges', 20, 'adults', 4, 'Who was the priest serving at Bethel that Israel consulted, and what is significant about his ancestry?', 'Phinehas the son of Eleazar the son of Aaron — meaning the high priest of Aaron''s line was present, lending legitimate covenantal authority to the inquiry and implying the tabernacle was briefly stationed at Bethel', 'An unnamed Levite priest with no significant ancestry', 'Jonathan the grandson of Moses (or Manasseh) from Dan''s shrine', 'The text does not identify the priest at Bethel', 'a', 'Judges 20:28 — "And Phinehas, the son of Eleazar, the son of Aaron, stood before it in those days." The presence of Phinehas, Aaron''s grandson, who also appears in Numbers 25 as zealous for God''s honour, dates the narrative and identifies legitimate priestly authority.'),
('Judges', 20, 'adults', 5, 'What is the significance of the ambush strategy used against Gibeah compared to the conquest narrative in Joshua 8?', 'It precisely mirrors Joshua''s ambush of Ai (Josh. 8:2-22): lure the enemy out of the city, spring an ambush from hiding, then signal with fire as the city burns — suggesting a conscious literary parallel connecting Benjamin''s fall with Ai''s destruction', 'The similarity is purely tactical and there is no literary connection to Joshua 8', 'Joshua''s Ai ambush used fire signals while Israel used trumpet signals at Gibeah, making them different', 'The Gibeah ambush was divinely mandated while Joshua''s was purely human strategy', 'a', 'Judges 20:38 — "Now there was an appointed sign between the men of Israel and the liers in wait, that they should make a great flame with smoke rise up out of the city." Joshua 8:8 — "it shall be, when ye have taken the city, that ye shall set the city on fire." The structural parallel is unmistakable.'),
('Judges', 20, 'adults', 6, 'How does the civil war against Benjamin illustrate the problem of justice versus mercy that recurs throughout the Hebrew Bible?', 'Israel pursued justice so absolutely that they nearly exterminated a tribe of God''s own people — raising the question of whether vengeance administered by fallen human institutions can ever achieve true justice without crossing into excessive destruction', 'Justice was perfectly administered and the outcome was exactly right', 'Israel showed too much mercy by allowing six hundred to survive', 'The war was unjust because Benjamin had only a few guilty individuals among many innocent', 'a', 'Judges 20:48 — "And the men of Israel turned again upon the children of Benjamin, and smote them with the edge of the sword, as well the men of every city, as the beast, and all that came to hand: also they set on fire all the cities that they came to." The thoroughness of destruction mirrors the herem of Canaanite warfare turned against Israel''s own kin.'),
('Judges', 20, 'adults', 7, 'What does the total casualty count across chapters 20-21 — approximately forty thousand Israelites dead plus nearly all of Benjamin — suggest about the cost of sin?', 'The sin of a relatively small group at Gibeah generated a catastrophic ripple of communal violence costing tens of thousands of lives — illustrating the corporate and generational weight of unaddressed sin within a covenant community', 'The casualties are typical for ancient warfare and have no special theological significance', 'The deaths were primarily Benjamite and thus were simply divine punishment with no wider lesson', 'The numbers suggest the text is symbolic, not historical', 'a', 'Judges 20:21,25,46-47 — 22,000 + 18,000 Israelites fell; 25,100 Benjamites fell; only 600 of Benjamin survived. A single night of wickedness at Gibeah generated losses that dwarfed any battle against an external enemy in Judges.'),
('Judges', 20, 'adults', 8, 'What does the Levite''s altered account of events in Judges 20:4-6 compared to the narrative of chapter 19 suggest about narrative reliability and human testimony?', 'His account omits his own role in sending his concubine outside and simplifies the event — the divergence between his testimony and the narrator''s account introduces a layer of unreliable testimony, inviting readers to interrogate the motives of those who call for holy war', 'The two accounts are completely consistent and the apparent difference is a translation issue', 'The Levite''s account is the more reliable since he was an eyewitness', 'The narrator''s account contains errors that the Levite''s testimony corrects', 'a', 'Judges 20:5 — "And the men of Gibeah rose against me, and beset the house round about upon me by night...and my concubine have they forced, that she is dead." Judges 19:25 — "so the man took his concubine, and brought her forth unto them." The Levite omits his own agency in handing her over, a significant omission that the careful reader of both chapters will notice.');
